   124→static void free_buffer_ring(buffer_ring_t *buf)
   125→{
   126→	int i;
   127→	for (i = 0; i < 3; ++i) {
   128→		free(buf->bufs[i]);
   129→		buf->bufs[i] = NULL;
   130→	}
   131→	buf->timestamp = 0;
   132→	buf->valid = 0;
   133→	buf->fmt = -1;
   134→	buf->res = -1;
   135→}
