   137→static void producer_cb_inner(freenect_device *dev, void *data, uint32_t timestamp, buffer_ring_t *buf, set_buffer_t set_buffer)
   138→{
   139→	pthread_mutex_lock(&buf->lock);
   140→	assert(data == buf->bufs[2]);
   141→	void *temp_buf = buf->bufs[1];
   142→	buf->bufs[1] = buf->bufs[2];
   143→	buf->bufs[2] = temp_buf;
   144→	set_buffer(dev, temp_buf);
   145→	buf->timestamp = timestamp;
   146→	buf->valid = 1;
   147→	pthread_cond_signal(&buf->cb_cond);
   148→	pthread_mutex_unlock(&buf->lock);
   149→}
   150→
   151→static void video_producer_cb(freenect_device *dev, void *data, uint32_t timestamp)
   152→{
   153→	producer_cb_inner(dev, data, timestamp, &((sync_kinect_t *)freenect_get_user(dev))->video, freenect_set_video_buffer);
   154→}
   155→
   156→static void depth_producer_cb(freenect_device *dev, void *data, uint32_t timestamp)
   157→{
   158→	producer_cb_inner(dev, data, timestamp, &((sync_kinect_t *)freenect_get_user(dev))->depth, freenect_set_depth_buffer);
   159→}
