   161→/* You should only use these functions to manipulate the pending_runloop_tasks_lock*/
   162→static void pending_runloop_tasks_inc(void)
   163→{
   164→	pthread_mutex_lock(&pending_runloop_tasks_lock);
   165→	assert(pending_runloop_tasks >= 0);
   166→	++pending_runloop_tasks;
   167→	pthread_mutex_unlock(&pending_runloop_tasks_lock);
   168→}
   169→
   170→static void pending_runloop_tasks_dec(void)
   171→{
   172→	pthread_mutex_lock(&pending_runloop_tasks_lock);
   173→	--pending_runloop_tasks;
   174→	assert(pending_runloop_tasks >= 0);
   175→	if (!pending_runloop_tasks)
   176→		pthread_cond_signal(&pending_runloop_tasks_cond);
   177→	pthread_mutex_unlock(&pending_runloop_tasks_lock);
   178→}
   179→
   180→static void pending_runloop_tasks_wait_zero(void)
   181→{
   182→	pthread_mutex_lock(&pending_runloop_tasks_lock);
   183→	while (pending_runloop_tasks)
   184→		pthread_cond_wait(&pending_runloop_tasks_cond, &pending_runloop_tasks_lock);
   185→	pthread_mutex_unlock(&pending_runloop_tasks_lock);
   186→}
   187→
   188→static void *init(void *unused)
   189→{
   190→	pending_runloop_tasks_wait_zero();
   191→	pthread_mutex_lock(&runloop_lock);
   192→	while (thread_running && freenect_process_events(ctx) >= 0) {
   193→		pthread_mutex_unlock(&runloop_lock);
   194→		// NOTE: This lets you run tasks while process_events isn't running
   195→		pending_runloop_tasks_wait_zero();
   196→		pthread_mutex_lock(&runloop_lock);
   197→	}
   198→	// Go through each device, call stop video, close device
   199→	int i;
   200→	for (i = 0; i < MAX_KINECTS; ++i) {
   201→		if (kinects[i]) {
   202→			freenect_stop_video(kinects[i]->dev);
   203→			freenect_stop_depth(kinects[i]->dev);
   204→			freenect_set_user(kinects[i]->dev, NULL);
   205→			freenect_close_device(kinects[i]->dev);
   206→			free_buffer_ring(&kinects[i]->video);
   207→			free_buffer_ring(&kinects[i]->depth);
   208→			free(kinects[i]);
   209→			kinects[i] = NULL;
   210→		}
   211→	}
   212→	freenect_shutdown(ctx);
   213→	pthread_mutex_unlock(&runloop_lock);
   214→	return NULL;
   215→}
   216→
   217→static void init_thread(void)
   218→{
   219→	thread_running = 1;
   220→	freenect_init(&ctx, 0);
   221→	// We claim both the motor and the camera, because we can't know in advance
   222→	// which devices the caller will want, and the c_sync interface doesn't
   223→	// support audio, so there's no reason to claim the device needlessly.
   224→	freenect_select_subdevices(ctx, (freenect_device_flags)(FREENECT_DEVICE_MOTOR | FREENECT_DEVICE_CAMERA));
   225→	pthread_create(&thread, NULL, init, NULL);
   226→}
   227→
   228→static int change_video_format(sync_kinect_t *kinect, freenect_resolution res, freenect_video_format fmt)
   229→{
   230→	freenect_stop_video(kinect->dev);
   231→	free_buffer_ring(&kinect->video);
   232→	if (alloc_buffer_ring_video(res, fmt, &kinect->video))
   233→		return -1;
   234→	freenect_set_video_mode(kinect->dev, freenect_find_video_mode(res, fmt));
   235→	freenect_set_video_buffer(kinect->dev, kinect->video.bufs[2]);
   236→	freenect_start_video(kinect->dev);
   237→	return 0;
   238→}
   239→
   240→static int change_depth_format(sync_kinect_t *kinect, freenect_resolution res, freenect_depth_format fmt)
   241→{
   242→	freenect_stop_depth(kinect->dev);
   243→	free_buffer_ring(&kinect->depth);
   244→	if (alloc_buffer_ring_depth(res, fmt, &kinect->depth))
   245→		return -1;
   246→	freenect_set_depth_mode(kinect->dev, freenect_find_depth_mode(res, fmt));
   247→	freenect_set_depth_buffer(kinect->dev, kinect->depth.bufs[2]);
   248→	freenect_start_depth(kinect->dev);
   249→	return 0;
   250→}
   251→
   252→static sync_kinect_t *alloc_kinect(int index)
   253→{
   254→	sync_kinect_t *kinect = (sync_kinect_t*)malloc(sizeof(sync_kinect_t));
   255→	if (freenect_open_device(ctx, &kinect->dev, index) < 0) {
   256→		free(kinect);
   257→		return NULL;
   258→	}
   259→	int i;
   260→	for (i = 0; i < 3; ++i) {
   261→		kinect->video.bufs[i] = NULL;
   262→		kinect->depth.bufs[i] = NULL;
   263→	}
   264→	kinect->video.fmt = -1;
   265→	kinect->video.res = -1;
   266→	kinect->depth.fmt = -1;
   267→	kinect->depth.res = -1;
   268→	freenect_set_video_callback(kinect->dev, video_producer_cb);
   269→	freenect_set_depth_callback(kinect->dev, depth_producer_cb);
   270→	pthread_mutex_init(&kinect->video.lock, NULL);
   271→	pthread_mutex_init(&kinect->depth.lock, NULL);
   272→	pthread_cond_init(&kinect->video.cb_cond, NULL);
   273→	pthread_cond_init(&kinect->depth.cb_cond, NULL);
   274→	return kinect;
   275→}
   276→
   277→static int setup_kinect(int index, int res, int fmt, int is_depth)
   278→{
   279→	pending_runloop_tasks_inc();
   280→	pthread_mutex_lock(&runloop_lock);
   281→	int thread_running_prev = thread_running;
   282→	if (!thread_running)
   283→		init_thread();
   284→	if (!kinects[index]) {
   285→		kinects[index] = alloc_kinect(index);
   286→	}
   287→	if (!kinects[index]) {
   288→		printf("Error: Invalid index [%d]\n", index);
   289→		// If we started the thread, we need to bring it back
   290→		if (!thread_running_prev) {
   291→			thread_running = 0;
   292→			pthread_mutex_unlock(&runloop_lock);
   293→			pending_runloop_tasks_dec();
   294→			pthread_join(thread, NULL);
   295→		} else {
   296→			pthread_mutex_unlock(&runloop_lock);
   297→			pending_runloop_tasks_dec();
   298→		}
   299→		return -1;
   300→	}
   301→	freenect_set_user(kinects[index]->dev, kinects[index]);
   302→	buffer_ring_t *buf;
   303→	if (is_depth)
   304→		buf = &kinects[index]->depth;
   305→	else
   306→		buf = &kinects[index]->video;
   307→	pthread_mutex_lock(&buf->lock);
   308→	if ((buf->fmt != fmt) || (buf->res != res))
   309→	{
   310→		if (is_depth)
   311→			change_depth_format(kinects[index], (freenect_resolution)res, (freenect_depth_format)fmt);
   312→		else
   313→			change_video_format(kinects[index], (freenect_resolution)res, (freenect_video_format)fmt);
   314→	}
   315→	pthread_mutex_unlock(&buf->lock);
   316→	pthread_mutex_unlock(&runloop_lock);
   317→	pending_runloop_tasks_dec();
   318→	return 0;
   319→}
   320→
   321→static int sync_get(void **data, uint32_t *timestamp, buffer_ring_t *buf)
   322→{
   323→	pthread_mutex_lock(&buf->lock);
   324→	// If there isn't a frame ready for us
   325→	while (!buf->valid)
   326→		pthread_cond_wait(&buf->cb_cond, &buf->lock);
   327→	void *temp_buf = buf->bufs[0];
   328→	*data = buf->bufs[0] = buf->bufs[1];
   329→	buf->bufs[1] = temp_buf;
   330→	buf->valid = 0;
   331→	*timestamp = buf->timestamp;
   332→	pthread_mutex_unlock(&buf->lock);
   333→	return 0;
   334→}
   335→
   336→
   337→/* 
   338→  Use this to make sure the runloop is locked and no one is in it. Then you can
   339→  call arbitrary functions from libfreenect.h in a safe way. If the kinect with
   340→  this index has not been initialized yet, then it will try to set it up. If 
   341→  this function is successful, then you can access kinects[index]. Don't forget
   342→  to unlock the runloop when you're done.
   343→  
   344→  Returns 0 if successful, nonzero if kinect[index] is unvailable
   345→ */ 
   346→static int runloop_enter(int index)
   347→{
   348→	if (index < 0 || index >= MAX_KINECTS) {
   349→		printf("Error: Invalid index [%d]\n", index);
   350→		return -1;
   351→	}
   352→	if (!thread_running || !kinects[index])
   353→		if (setup_kinect(index, FREENECT_RESOLUTION_MEDIUM, FREENECT_DEPTH_11BIT, 1))
   354→			return -1;
   355→		
   356→	pending_runloop_tasks_inc();
   357→	pthread_mutex_lock(&runloop_lock);
   358→	return 0;
   359→}
   360→
   361→static void runloop_exit()
   362→{
   363→	pthread_mutex_unlock(&runloop_lock);
   364→	pending_runloop_tasks_dec();
   365→}
   366→
   367→int freenect_sync_get_video_with_res(void **video, uint32_t *timestamp, int index,
   368→        freenect_resolution res, freenect_video_format fmt)
   369→{
   370→	if (index < 0 || index >= MAX_KINECTS) {
   371→		printf("Error: Invalid index [%d]\n", index);
   372→		return -1;
   373→	}
   374→	if (!thread_running || !kinects[index] || kinects[index]->video.fmt != fmt || kinects[index]->video.res != res)
   375→		if (setup_kinect(index, res, fmt, 0))
   376→			return -1;
   377→	sync_get(video, timestamp, &kinects[index]->video);
   378→	return 0;
   379→}
   380→
   381→int freenect_sync_get_video(void **video, uint32_t *timestamp, int index, freenect_video_format fmt)
   382→{
   383→    return freenect_sync_get_video_with_res(video, timestamp, index, FREENECT_RESOLUTION_MEDIUM, fmt);
   384→}
   385→
   386→int freenect_sync_get_depth_with_res(void **depth, uint32_t *timestamp, int index,
   387→        freenect_resolution res, freenect_depth_format fmt)
   388→{
   389→	if (index < 0 || index >= MAX_KINECTS) {
   390→		printf("Error: Invalid index [%d]\n", index);
   391→		return -1;
   392→	}
   393→	if (!thread_running || !kinects[index] || kinects[index]->depth.fmt != fmt
   394→            || kinects[index]->depth.res != res)
   395→		if (setup_kinect(index, res, fmt, 1))
   396→			return -1;
   397→	sync_get(depth, timestamp, &kinects[index]->depth);
   398→	return 0;
   399→}
   400→
   401→int freenect_sync_get_depth(void **depth, uint32_t *timestamp, int index, freenect_depth_format fmt)
   402→{
   403→    return freenect_sync_get_depth_with_res(depth, timestamp, index, FREENECT_RESOLUTION_MEDIUM, fmt);
   404→}
   405→
   406→int freenect_sync_get_tilt_state(freenect_raw_tilt_state **state, int index)
   407→{
   408→	if (runloop_enter(index)) return -1;
   409→	freenect_update_tilt_state(kinects[index]->dev);
   410→	*state = freenect_get_tilt_state(kinects[index]->dev);  
   411→	runloop_exit();
   412→	return 0;
   413→}
   414→
   415→int freenect_sync_set_tilt_degs(int angle, int index) {
   416→	if (runloop_enter(index)) return -1;
   417→	freenect_set_tilt_degs(kinects[index]->dev, angle);
   418→	runloop_exit();
   419→	return 0;
   420→}
   421→
   422→int freenect_sync_set_led(freenect_led_options led, int index) {
   423→	if (runloop_enter(index)) return -1;
   424→	freenect_set_led(kinects[index]->dev, led);
   425→	runloop_exit();
   426→	return 0;
   427→}
   428→
   429→int freenect_sync_camera_to_world(int cx, int cy, int wz, double* wx, double* wy, int index) {
   430→	if (runloop_enter(index)) return -1;
   431→	freenect_camera_to_world(kinects[index]->dev, cx, cy, wz, wx, wy);
   432→	runloop_exit();
   433→	return 0;
   434→}
